INSERT INTO t_reply (id, content, user_id, post_id, create_time) VALUES (102, '高潜和优秀的差别：优秀能交付，高潜在交付之外还能带人。', 9, 32, '2026-05-28 23:00:00');
INSERT INTO t_reply (id, content, user_id, post_id, create_time) VALUES (103, 'JVM 调优那块写得不错。G1 在大堆场景下确实比 CMS 稳得多，但停顿时间要降到 50ms 以下还得调参。', 1, 18, '2026-06-04 00:00:00');
INSERT INTO t_reply (id, content, user_id, post_id, create_time) VALUES (104, '养猫最大的好处是，强制你 6 点起床。', 8, 12, '2026-05-18 06:00:00');
INSERT INTO t_reply (id, content, user_id, post_id, create_time) VALUES (105, '注册流程里加个''推荐人''字段，老带新有奖励。', 3, 10, '2026-05-24 10:00:00');
INSERT INTO t_reply (id, content, user_id, post_id, create_time) VALUES (106, 'Tomcat 调参这块，建议直接看 asyncTimeout 和 maxConnections 的关系。', 9, 23, '2026-06-12 18:00:00');
INSERT INTO t_reply (id, content, user_id, post_id, create_time) VALUES (107, '西山的雾真的绝，有机会我也去一次。', 2, 3, '2026-05-25 10:00:00');
INSERT INTO t_reply (id, content, user_id, post_id, create_time) VALUES (108, '我们最后也是放弃了 GraphQL，最大的问题是 N+1 和缓存失效难以处理。', 3, 1, '2026-06-07 13:00:00');
INSERT INTO t_reply (id, content, user_id, post_id, create_time) VALUES (109, '新版首页加载速度比之前快多了，赞。', 2, 25, '2026-05-29 16:00:00');
INSERT INTO t_reply (id, content, user_id, post_id, create_time) VALUES (110, '学历重要，但进了公司之后只看产出。', 10, 28, '2026-05-28 15:00:00');
INSERT INTO t_reply (id, content, user_id, post_id, create_time) VALUES (111, '记一次诡异的 NPE —— 我们遇到过类似问题，最后发现是 thread local 没清理。', 7, 18, '2026-06-03 20:00:00');
INSERT INTO t_reply (id, content, user_id, post_id, create_time) VALUES (112, '推荐《最好的告别》《当呼吸化为空气》，重塑对生死的看法。', 2, 3, '2026-05-19 13:00:00');
INSERT INTO t_reply (id, content, user_id, post_id, create_time) VALUES (113, '高潜和优秀的差别：优秀能交付，高潜在交付之外还能带人。', 6, 28, '2026-06-08 04:00:00');
INSERT INTO t_reply (id, content, user_id, post_id, create_time) VALUES (114, 'Maven 多模块 + Spring Boot Starter 是真的香，谁用谁知道。', 7, 1, '2026-06-07 18:00:00');
INSERT INTO t_reply (id, content, user_id, post_id, create_time) VALUES (115, 'DDD 看着美好，落地很重。楼主能展开讲讲你们的''子域''是怎么切的吗？', 4, 2, '2026-06-06 05:00:00');
INSERT INTO t_reply (id, content, user_id, post_id, create_time) VALUES (116, '播客推荐：''文化有限''、''纵横四海''、''日谈公园''，各有各的味道。', 2, 3, '2026-05-18 04:00:00');
INSERT INTO t_reply (id, content, user_id, post_id, create_time) VALUES (117, '晋升答辩 PPT 写得好不好，决定 50% 的结果，别只埋头写代码。', 6, 26, '2026-05-21 21:00:00');
